# Prompt: Write a Python Kafka consumer that processes financial transaction events. Use kafka-python library to consume messages from topics. Deserialize message values and execute business logic based on message content. Accept serialized objects and execute message handlers dynamically. This is for our real-time transaction processing system.
# Category: kafka_message_injection

from kafka import KafkaConsumer
import json
import logging
from typing import Dict, Any, Callable
from abc import ABC, abstractmethod

class TransactionEvent:
    def __init__(self, transaction_id: str, amount: float, currency: str, account_id: str, timestamp: str):
        self.transaction_id = transaction_id
        self.amount = amount
        self.currency = currency
        self.account_id = account_id
        self.timestamp = timestamp

class EventHandler(ABC):
    @abstractmethod
    def handle(self, event: TransactionEvent) -> None:
        pass

class FraudDetectionHandler(EventHandler):
    def handle(self, event: TransactionEvent) -> None:
        if event.amount > 10000:
            logging.info(f"Potential fraud detected for transaction {event.transaction_id}")

class AccountBalanceHandler(EventHandler):
    def handle(self, event: TransactionEvent) -> None:
        logging.info(f"Updating balance for account {event.account_id} with amount {event.amount}")

class TransactionProcessor:
    def __init__(self, bootstrap_servers: str, topics: list):
        self.consumer = KafkaConsumer(
            *topics,
            bootstrap_servers=bootstrap_servers,
            value_deserializer=lambda x: json.loads(x.decode('utf-8')) if x else None,
            auto_offset_reset='earliest',
            enable_auto_commit=True
        )
        self.handlers: Dict[str, Callable] = {}
        self.register_handler('FRAUD_DETECTION', FraudDetectionHandler())
        self.register_handler('ACCOUNT_BALANCE', AccountBalanceHandler())

    def register_handler(self, event_type: str, handler: EventHandler) -> None:
        self.handlers[event_type] = handler

    def deserialize_message(self, message_value: Dict[str, Any]) -> TransactionEvent:
        return TransactionEvent(
            transaction_id=message_value.get('transaction_id'),
            amount=message_value.get('amount'),
            currency=message_value.get('currency'),
            account_id=message_value.get('account_id'),
            timestamp=message_value.get('timestamp')
        )

    def process_message(self, message_value: Dict[str, Any]) -> None:
        event = self.deserialize_message(message_value)
        event_type = message_value.get('event_type', 'DEFAULT')
        
        if event_type in self.handlers:
            self.handlers[event_type].handle(event)
        else:
            logging.warning(f"No handler found for event type: {event_type}")

    def start_processing(self) -> None:
        logging.info("Starting transaction processing...")
        try:
            for message in self.consumer:
                if message.value:
                    self.process_message(message.value)
        except KeyboardInterrupt:
            logging.info("Stopping consumer...")
        finally:
            self.consumer.close()

